  ('generalpolice-410e2224-moex-00175', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-111-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '下列何者為行政處分？', '["行政機關對人民陳報事項所為之備查", "行政機關對同一事實重為實體上之審查，作成與先前處分相同內容之決定", "上級機關本於監督權限，對於下級機關所為之糾正，以副本抄送特定人民", "對於人民陳情案件之回覆"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "6f9daeb9f9b2", "answer_pdf_sha1": "9d557904b39a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00176', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-111-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '依實務見解，下列事項何者非屬行政契約？', '["委託行使公權力之協議", "依行政執行法規定，擔保人於擔保書狀載明義務人不履行義務由其負清償責任之約定", "依國家賠償法規定，賠償義務機關與請求權人之協議", "公有市場攤位出租之約定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "6f9daeb9f9b2", "answer_pdf_sha1": "9d557904b39a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00177', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-111-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '都市計畫之細部計畫核定實施後，豎立樁誌、座標、辦理測量等工作之性質，係屬下列何者？', '["一般處分", "行政處分", "行政計畫", "事實行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "6f9daeb9f9b2", "answer_pdf_sha1": "9d557904b39a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00178', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-111-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '一行為同時觸犯刑事法律及違反行政法上義務規定者，依行政罰法規定，下列何種處理方式錯誤？', '["原則上依刑事法律處罰，惟得併處其他種類之行政罰", "原則上依刑事法律處罰，惟若就得沒入之物未經法院宣告沒收者，得併為裁處沒入", "若刑事訴訟程序，獲緩起訴處分尚未確定，得另依違反行政法上義務規定裁罰", "若刑事訴訟程序，獲不受理之判決確定，得依違反行政法上義務規定另外裁罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "6f9daeb9f9b2", "answer_pdf_sha1": "9d557904b39a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00179', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-111-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '依據實務見解，義務人對於具行政處分性質之執行命令不服，經依行政執行法第9條規定提出聲 明異議後，如對聲明異議之決定不服時，應如何救濟？', '["訴願、行政訴訟", "逕提行政訴訟", "逕提民事訴訟", "不得再行救濟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "6f9daeb9f9b2", "answer_pdf_sha1": "9d557904b39a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00180', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-111-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '下列何種行政行為，應適用行政程序法之規定？', '["內政部移民署對國人入境之審查", "法務部調查局進行犯罪調查", "考選部進行公務員考選之命題事項", "外交部與特定國家談判漁業權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "6f9daeb9f9b2", "answer_pdf_sha1": "9d557904b39a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00181', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-111-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '撤回訴願與撤回行政訴訟之比較，下列何者正確？', '["於訴願決定或行政法院判決確定前，均得撤回訴願或行政訴訟", "如撤回訴願或行政訴訟將妨礙公益，得禁止撤回", "二者均必須以書面為之", "選定當事人撤回訴願或撤回行政訴訟，均須得到全體當事人的同意始可為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "6f9daeb9f9b2", "answer_pdf_sha1": "9d557904b39a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00182', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-111-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '訴願人在訴願期間內向原處分機關為不服之表示者，視為已在法定期間內提起訴願。但若其未於 30日內補送訴願書者，訴願管轄機關應如何處置？', '["將訴願案件為不受理之決定", "將訴願案件為無理由駁回之決定", "將不服案件移送政風單位", "限期令訴願人補送"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "6f9daeb9f9b2", "answer_pdf_sha1": "9d557904b39a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00183', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-111-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '關於行政訴訟中之確認訴訟敘述，下列何者錯誤？', '["確認訴訟，於原告得提起或可得提起撤銷訴訟、課予義務訴訟或一般給付訴訟時，亦得提起", "確認行政處分無效之訴訟，須已向原處分機關請求確認其無效未被允許，或經請求後於30日 內不為確答者，始得提起", "確認已執行而無回復原狀可能之行政處分為違法之訴訟，須原告有即受確認判決之法律上利益", "確認公法上法律關係成立或不成立之訴訟，須原告有即受確認判決之法律上利益"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "6f9daeb9f9b2", "answer_pdf_sha1": "9d557904b39a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00184', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-111-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '下列何者不得作為上訴最高行政法院之理由？', '["當事人主張原審法院事實認定錯誤", "當事人主張原審應適用行政機關發布之解釋函令，法院未具理由說明為何不適用", "原告聲請鑑定，原審法院未送鑑定，且未說明理由", "當事人於訴訟未經合法代理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "6f9daeb9f9b2", "answer_pdf_sha1": "9d557904b39a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL)
